"use strict";

const fs = require("fs");
const path = require("path");

const root = path.resolve(__dirname, "..");
const sources = [
  "max/javascript/live_value_helpers.js",
  "max/javascript/naming_engine.js",
  "max/javascript/live_controller.js",
];
const banner = "/* GENERATED by scripts/build_max_js_bundle.js. Edit max/javascript sources, then rebuild. */\n";
const content = banner + sources.map((source) => `\n/* BEGIN ${source} */\n${fs.readFileSync(path.join(root, source), "utf8")}\n/* END ${source} */\n`).join("");
for (const target of ["slice_labeler_bundle.js", "slice_labeler_bundle_v2.js"]) {
  fs.writeFileSync(path.join(root, "max/patchers", target), content, "utf8");
}

for (const [source, target] of [
  ["max/javascript/results_controller.js", "max/patchers/slice_labeler_results_bundle.js"],
  ["max/javascript/settings_controller.js", "max/patchers/slice_labeler_settings_bundle.js"],
]) {
  fs.writeFileSync(path.join(root, target), `/* GENERATED by scripts/build_max_js_bundle.js from ${source}. */\n${fs.readFileSync(path.join(root, source), "utf8")}`, "utf8");
}
